{"code":"// Get all merged PRs that close a Linear issue
const prs = github.list_pull_requests({ state: "merged" });
const prsWithLinear = prs.filter(p => p.closes_linear != null);
`${prsWithLinear.length} merged PRs close a Linear issue. IDs: ${prsWithLinear.map(p => p.closes_linear).join(', ')}`"}

{"code":"// Now match: merged PRs whose Linear issue state is NOT 'done'
const result = [];
for (const pr of prsWithLinear) {
  const issue = linear.get_issue({ id: pr.closes_linear });
  if (issue.state !== 'done') {
    result.push({ pr_number: pr.number, linear_id: issue.id, linear_state: issue.state });
  }
}
result.length + " matching PRs: " + JSON.stringify(result, null, 2)"}
